    19→ */
    20→class ConciseSetGeneratorTest {
    21→
    22→    // ==================== Helper Methods ====================
    23→
    24→    /**
    25→     * Creates a TestCase with the given integer arguments.
    26→     */
    27→    private TestCase createTestCase(int... args) {
    28→        List<APyObj> objArgs = new ArrayList<>();
    29→        for (int arg : args) {
    30→            objArgs.add(new PyIntObj(arg));
    31→        }
    32→        return new TestCase(objArgs);
    33→    }
    34→
    35→    /**
    36→     * Creates a TestCase with the given float arguments.
    37→     */
    38→    private TestCase createFloatTestCase(double... args) {
    39→        List<APyObj> objArgs = new ArrayList<>();
