    41→            objArgs.add(new PyFloatObj(arg));
    42→        }
    43→        return new TestCase(objArgs);
    44→    }
    45→
    46→    /**
    47→     * Creates a deep copy of a list of test cases.
    48→     */
    49→    private List<TestCase> copyAllCases(List<TestCase> allCases) {
    50→        List<TestCase> copy = new ArrayList<>();
    51→        for (TestCase tc : allCases) {
    52→            List<APyObj> argsCopy = new ArrayList<>(tc.getArgs());
    53→            copy.add(new TestCase(argsCopy));
    54→        }
    55→        return copy;
    56→    }
    57→
    58→    /**
    59→     * Creates a deep copy of caseToFiles.
    60→     */
    61→    private List<Set<Integer>> copyCaseToFiles(List<Set<Integer>> caseToFiles) {
    62→        List<Set<Integer>> copy = new ArrayList<>();
    63→        for (Set<Integer> set : caseToFiles) {
    64→            copy.add(new HashSet<>(set));
    65→        }
    66→        return copy;
    67→    }
    68→
    69→    /**
    70→     * Creates a deep copy of wrongSet.
    71→     */
    72→    private Set<Integer> copyWrongSet(Set<Integer> wrongSet) {
    73→        return new HashSet<>(wrongSet);
    74→    }
    75→
    76→    // ==================== Mutation Tests (4.0 pts total) ====================
    77→
    78→    /**
    79→     * Tests that setCover does not mutate the allCases list.
    80→     * (1.0 pt)
    81→     */
    82→    @Test
    83→    void testDoesNotMutateAllCases() {
    84→        // Setup: 3 test cases, 3 files, each test catches one file
    85→        List<TestCase> allCases = Arrays.asList(
    86→            createTestCase(1),
    87→            createTestCase(2),
    88→            createTestCase(3)
    89→        );
    90→        List<Set<Integer>> caseToFiles = Arrays.asList(
    91→            new HashSet<>(Arrays.asList(0)),
    92→            new HashSet<>(Arrays.asList(1)),
    93→            new HashSet<>(Arrays.asList(2))
    94→        );
    95→        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2));
    96→
    97→        // Make copies for comparison
    98→        List<TestCase> originalAllCases = copyAllCases(allCases);
    99→
   100→        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
   101→        ConciseSetGenerator.setCover(results);
   102→
   103→        // Verify allCases was not mutated
