     7→/**
     8→ * A class for running a test suite. Encapsulates the ability to run the test suite on a
     9→ * reference implementation to generate the expected results, the ability to create a
    10→ * "wrapper" file for comparing actual results to these expected results, and the ability
    11→ * to run the test suite on a set of files and identify which test cases each file fails
    12→ * on.
    13→ */
    14→public class Tester {
    15→
    16→    /**
    17→     * The name of the function under test.
    18→     */
    19→    private final String funcName;
    20→
    21→    /**
    22→     * The absolute path to the file containing the reference solution (known to be
    23→     * correct).
    24→     */
    25→    private final String solutionPath;
    26→
    27→    /**
    28→     * The absolute path to the directory containing the student implementations.
    29→     */
    30→    private final String implDirPath;
    31→
    32→    /**
    33→     * The set of test cases to be executed on the reference solution.
    34→     */
    35→    private final List<TestCase> tests;
    36→
    37→    /**
    38→     * Constructor for a Tester, which initializes all of the fields using the given
    39→     * inputs.
    40→     *
    41→     * @param funcName     the name of the function under test
    42→     * @param solutionPath the absolute path to the file containing the reference
    43→     *                     implementation
    44→     * @param implDirPath  the absolute path to the directory containing the student
    45→     *                     implementations
    46→     * @param tests        the list of test cases to be executed
    47→     */
    48→    public Tester(String funcName, String solutionPath, String implDirPath,
    49→                  List<TestCase> tests) {
    50→        this.funcName = funcName;
    51→        this.implDirPath = implDirPath;
    52→        this.solutionPath = solutionPath;
    53→        this.tests = tests;
    54→    }
    55→
    56→    /**
    57→     * Computes the expected results by running each test case on the solution file.
    58→     * Stores the results in a list (which is returned) and also creates a .py file
    59→     * containing an equivalent list of the results.
    60→     *
    61→     * @return a list where the i-th element is the result (a string) of running the i-th
    62→     * test case on the reference solution
    63→     * @throws IOException if the path to the solution is invalid
    64→     * @throws InterruptedException if the process is interrupted
    65→     */
    66→    public List<String> computeExpectedResults() throws IOException, InterruptedException {
    67→        // Write an appropriate footer to the solution file to make it executable from
    68→        // the command-line, if the footer doesn't exist already
    69→        this.appendToSolution();
    70→
    71→        // Run each test case on the solution file and gather the results in a map
    72→        List<String> results = new ArrayList<>();
    73→        for (int i = 0; i < this.tests.size(); i++) {
    74→            List<String> args = this.getExpTestArgs(i);
    75→            String result = this.runTestHelper(args);
    76→            results.add(result);
    77→        }
    78→
    79→        // Write the expected results to a .py file, so that they can be accessed via
    80→        // the wrapper. These cached results allow us to only run the solution once per
    81→        // test rather than having to run it once per test per buggy implementation.
    82→        this.outputExpectedResults(results);
    83→
    84→        // Return the results
    85→        return results;
    86→    }
    87→
    88→    /**
    89→     * Runs all tests on all files in the directory of buggy implementations, comparing
    90→     * the outputs to the pre-generated expected results and returning the results in the
    91→     * form of a TestResults object.
    92→     *
    93→     * @return the results of testing
    94→     * @throws IOException if the path to the directory of buggy implementations is
    95→     *                     invalid
    96→     * @throws InterruptedException if the process is interrupted
    97→     */
    98→    public TestResults runTests() throws IOException, InterruptedException {
    99→        // Create the wrapper file
   100→        this.createWrapperFile();
   101→
   102→        // Initialize the outputs
   103→        List<Set<Integer>> caseToFiles = new ArrayList<>();
   104→        for (int i = 0; i < this.tests.size(); i++) {
   105→            caseToFiles.add(new HashSet<>());
   106→        }
   107→        Set<Integer> wrongSet = new HashSet<>();
   108→
   109→        // Get the list of all files in the input directory
   110→        var dir = new File(this.implDirPath);
   111→        String[] filenames = dir.list();
   112→        if (filenames == null) {
   113→            throw new IOException("Error: implDir is empty");
   114→        }
   115→        Arrays.sort(filenames);
   116→
   117→        // If implDirPath didn't actually point to a directory, files would be null
   118→        int trueIndex = 0;
   119→
   120→        // Test each individual file using all tests in the base test set
   121→        for (String filename : filenames) {
   122→            if (!filename.endsWith(".py") || filename.equals("wrapper.py")
   123→                    || filename.equals("expected.py")) {
   124→                continue;
   125→            }
   126→
   127→            // Run each test case on this file, keeping track of which ones caught
   128→            // errors
   129→            HashSet<Integer> caughtBy = new HashSet<>();
   130→            for (int testIndex = 0; testIndex < this.tests.size(); testIndex++) {
   131→                List<String> args = this.getTestArgs(testIndex, filename);
   132→                String result = this.runTestHelper(args);
   133→                if (!result.equals("True")) {
   134→                    caseToFiles.get(testIndex).add(trueIndex);
   135→                    caughtBy.add(testIndex);
   136→                }
