 1→package main.rice.test;
 2→
 3→import java.util.List;
 4→import java.util.Set;
 5→
 6→/**
 7→ * A representation of the results of running a series of tests on a series of files.
 8→ */
 9→public class TestResults {
10→
11→    /**
12→     * All test cases that were executed; each one is a wrapper around a series of
13→     * PyObjs.
14→     */
15→    private final List<TestCase> allCases;
16→
17→    /**
18→     * The results of testing, in the form of a list where the i-th element is the set of
19→     * integers representing the indices of the files that were caught by that i-th test
20→     * case in allCases.
21→     */
22→    private final List<Set<Integer>> caseToFiles;
23→
24→    /**
25→     * A set of integers representing the indices of the files that failed one or more
26→     * tests in allCases.
27→     */
28→    private final Set<Integer> wrongSet;
29→
30→    /**
31→     * Constructor for a TestResults object; initializes all fields.
32→     *
33→     * @param allCases    all test cases that were executed
34→     * @param caseToFiles a list where the i-th element is a set of integers representing
35→     *                    the files that were caught by the i-th test case in allCases
36→     * @param wrongSet    the set of all files that failed one or more tests in allCases
37→     */
38→    public TestResults(List<TestCase> allCases, List<Set<Integer>> caseToFiles,
39→                       Set<Integer> wrongSet) {
40→        this.allCases = allCases;
41→        this.caseToFiles = caseToFiles;
42→        this.wrongSet = wrongSet;
43→    }
44→
45→    /**
46→     * Returns the index-th test case in allCases, if index is within the bounds of
47→     * allCases; null otherwise.
48→     *
49→     * @param index the index of the test case to be returned
50→     * @return the index-th test case in allTests, if index is valid; null otherwise
51→     */
52→    public TestCase getTestCase(int index) {
53→        // Make sure the index is in bounds; if it's out of bounds, return null
54→        if (index >= this.allCases.size() || (this.allCases.size() == 0) || (index < 0)) {
55→            return null;
56→        }
57→        return this.allCases.get(index);
58→    }
59→
60→    /**
61→     * Returns the set of files that failed one or more test cases, where files are
62→     * represented by their indices.
63→     *
64→     * @return the set of files that failed one or more test cases
65→     */
66→    public Set<Integer> getWrongSet() {
67→        return this.wrongSet;
68→    }
69→
70→    /**
71→     * Returns the per-case list of files that each test case caught, where files are
72→     * represented by their indices.
73→     *
74→     * @return the per-case list of files that each test case caught
75→     */
76→    public List<Set<Integer>> getCaseToFiles() {
77→        return this.caseToFiles;
78→    }
79→}

 1→package main.rice.test;
 2→
 3→import main.rice.obj.APyObj;
 4→import java.util.List;
 5→
 6→/**
 7→ * A representation of a test case; a wrapper around its arguments, each of which is an
 8→ * APyObj.
 9→ */
10→public class TestCase {
11→
12→    /**
13→     * The list of arguments (Python objects) comprising this test case.
14→     */
15→    private final List<APyObj> args;
16→
17→    /**
18→     * Constructor for a TestCase; initializes its list of arguments to the input.
19→     *
20→     * @param args the list of arguments (Python objects) comprising this test case
21→     */
22→    public TestCase(List<APyObj> args) {
23→        this.args = args;
24→    }
25→
26→    /**
27→     * Returns the list of arguments comprising this test case.
28→     *
29→     * @return the list of arguments comprising this test case
30→     */
31→    public List<APyObj> getArgs() {
32→        return this.args;
33→    }
34→
35→    /**
36→     * Returns a string representation of this test's arguments.
37→     *
38→     * @return a string representation of this test's arguments
39→     */
40→    @Override
41→    public String toString() {
42→        return this.args.toString();
43→    }
44→
45→    /**
46→     * Compares this test's arguments to the input object's arguments (if it's a TestCase)
47→     * by value.
48→     *
49→     * @param obj the object to compare against
50→     * @return true if this is equivalent by value to obj; false otherwise
51→     */
52→    @Override
53→    public boolean equals(Object obj) {
54→        // If obj is not a TestCase, it's not equivalent
55→        if (!(obj instanceof TestCase other)) {
56→            return false;
57→        }
58→
59→        // Compare the lists of arguments for equality
60→        return this.args.equals(other.getArgs());
61→    }
62→
63→    /**
64→     * Computes a hash code based on this object's value, such that two objects that are
65→     * considered equal by .equals() will also have the same hash code.
66→     *
67→     * @return the hash code for this object
68→     */
69→    @Override
70→    public int hashCode() {
71→        return this.args.hashCode();
72→    }
73→}

